               _name = rtxUTF8StrJoin (pctxt, (OSUTF8CHAR *)"\"",  _identifier, (OSUTF8CHAR *)"\"", 0, 0);
               _nvp = rtxUTF8StrJoin (pctxt, _name, (OSUTF8CHAR *)":", _value, 0, 0);

